# 신규 용어 정의 (313개)
new_entries = [
    # ===== 치아 구조 (추가) =====
    {"term":"구개","category":"치아 구조","short":"입천장을 이루는 뼈와 점막","detail":"구개는 경구개(단단한 입천장)와 연구개(물렁 입천장)로 나뉩니다. 상악 임플란트, 구개열 수술, 틀니 지지 등에서 중요한 해부학적 구조입니다.","tags":["기본"],"synonyms":["입천장","Palate"]},
    {"term":"하악골","category":"치아 구조","short":"아래턱을 이루는 뼈","detail":"하악골(Mandible)은 얼굴에서 가장 크고 강한 뼈로, 아래 치아를 지지하고 씹는 기능을 담당합니다. 턱관절을 통해 두개골에 연결됩니다.","tags":["기본"],"synonyms":["아래턱뼈","Mandible"]},
    {"term":"상악골","category":"치아 구조","short":"위턱을 이루는 뼈","detail":"상악골(Maxilla)은 위 치아를 지지하고, 코 옆 부비동(상악동)을 포함하는 뼈입니다. 임플란트 시 상악동과의 관계가 중요합니다.","tags":["기본"],"synonyms":["위턱뼈","Maxilla"]},
    {"term":"치아 번호","category":"치아 구조","short":"치아를 식별하는 국제 번호 체계","detail":"FDI 번호 체계에서 치아를 2자리 숫자로 구분합니다. 첫째 자리는 사분면(1~4), 둘째 자리는 치아 순서(1~8)입니다. 예: 16번은 오른쪽 위 첫째 큰어금니입니다.","tags":["기본"],"synonyms":["FDI 번호","치식"]},
    {"term":"설면","category":"치아 구조","short":"치아의 혀 쪽 면","detail":"설면(Lingual Surface)은 치아에서 혀와 접하는 안쪽 면입니다. 설측 교정은 이 면에 브라켓을 부착합니다.","tags":["기본"],"synonyms":["Lingual"]},
    {"term":"협면","category":"치아 구조","short":"치아의 볼 쪽 면","detail":"협면(Buccal Surface)은 치아에서 볼과 접하는 바깥쪽 면입니다. 어금니 바깥면의 충치나 마모가 이 면에서 발생합니다.","tags":["기본"],"synonyms":["Buccal"]},
    {"term":"순면","category":"치아 구조","short":"앞니의 입술 쪽 면","detail":"순면(Labial Surface)은 앞니에서 입술과 접하는 바깥쪽 면입니다. 라미네이트, 미백 등 심미 치료의 주된 대상 부위입니다.","tags":["기본"],"synonyms":["Labial"]},
    {"term":"교합면","category":"치아 구조","short":"어금니의 씹는 면","detail":"교합면(Occlusal Surface)은 어금니 윗면으로, 음식을 씹을 때 위아래 치아가 접촉하는 면입니다. 실란트, 충치 치료가 가장 많이 이루어지는 부위입니다.","tags":["기본"],"synonyms":["Occlusal"]},
    {"term":"치간 유두","category":"치아 구조","short":"치아 사이의 삼각형 잇몸","detail":"치간 유두(Interdental Papilla)는 치아 사이를 채우는 삼각형 모양의 잇몸 조직입니다. 치주염이 진행되면 소실되어 '블랙 트라이앵글'이 생깁니다.","tags":["기본"],"synonyms":["Interdental Papilla"]},
    {"term":"치근 이개부","category":"치아 구조","short":"다근치 뿌리가 갈라지는 부위","detail":"치근 이개부(Furcation)는 어금니에서 뿌리가 2~3개로 나뉘는 지점입니다. 이 부위에 골 흡수가 진행되면 치료가 매우 어렵습니다.","tags":["기본"],"synonyms":["Furcation"]},

    # ===== 치과 질환 (추가) =====
    {"term":"과잉치","category":"치과 질환","short":"정상보다 많은 여분의 치아","detail":"과잉치(Supernumerary Tooth)는 정상 치아 수 이상으로 생기는 여분의 치아입니다. 상악 앞니 부위에 가장 흔하며(정중과잉치), 영구치 맹출을 방해할 수 있습니다.","tags":["질환"],"synonyms":["정중과잉치","Supernumerary"]},
    {"term":"선천성 결손치","category":"치과 질환","short":"태어날 때부터 치아가 없는 경우","detail":"선천성 결손치는 영구치 씨앗(치배)이 없어 치아가 나지 않는 상태입니다. 하악 소구치, 상악 측절치에 흔하며, 교정이나 임플란트로 치료합니다.","tags":["질환"],"synonyms":["무치증"]},
    {"term":"법랑질 저형성증","category":"치과 질환","short":"법랑질이 제대로 형성되지 않은 상태","detail":"법랑질 저형성증은 치아 발달 중 법랑질이 불완전하게 형성된 상태입니다. 치아 표면에 함몰, 변색, 거친 질감이 나타나며 충치에 취약합니다.","tags":["질환"],"synonyms":["Enamel Hypoplasia"]},
    {"term":"치아 맹출 장애","category":"치과 질환","short":"치아가 정상적으로 나오지 못하는 상태","detail":"치아 맹출 장애는 과잉치, 낭종, 공간 부족 등으로 영구치가 정상 시기에 나오지 못하는 상태입니다. 소아치과에서 조기 발견이 중요합니다.","tags":["질환","소아"],"link":"/treatments/pediatric"},
    {"term":"치아 외상","category":"치과 질환","short":"외부 충격에 의한 치아 손상","detail":"치아 외상은 넘어짐, 충돌 등 외부 충격으로 치아가 파절, 탈구, 함입되는 것입니다. 완전 탈구된 치아는 30분 이내에 재식하면 살릴 수 있습니다.","tags":["질환","외과"]},
    {"term":"치아 탈구","category":"치과 질환","short":"외상으로 치아가 원래 위치에서 벗어난 상태","detail":"치아 탈구는 불완전 탈구(치아가 흔들리거나 위치 변동)와 완전 탈구(치아가 완전히 빠짐)로 나뉩니다. 응급 상황으로 즉시 치과 방문이 필요합니다.","tags":["질환","외과"]},
    {"term":"치아 함입","category":"치과 질환","short":"치아가 뼈 속으로 밀려 들어간 상태","detail":"치아 함입(Intrusion)은 강한 충격으로 치아가 치조골 속으로 밀려 들어간 상태입니다. 소아에서 비교적 흔하며, 자연 재맹출을 기다리거나 교정으로 당겨냅니다.","tags":["질환","외과"]},
    {"term":"구강 헤르페스","category":"치과 질환","short":"입술이나 입 주변에 물집이 생기는 바이러스 질환","detail":"구강 헤르페스(HSV-1)는 입술, 잇몸, 구강 점막에 작은 물집이 생기는 질환입니다. 재발성이며 피로, 스트레스 시 악화됩니다. 항바이러스제로 치료합니다.","tags":["질환"],"synonyms":["구순포진","HSV-1"]},
    {"term":"구강 건조증","category":"치과 질환","short":"타액 분비 감소로 입이 마르는 상태","detail":"구강 건조증(Xerostomia)은 약물 부작용, 방사선 치료, 자가면역질환 등으로 침이 줄어드는 상태입니다. 충치·잇몸 질환 위험이 급증하므로 인공 타액 사용이 필요합니다.","tags":["질환"],"synonyms":["Xerostomia"]},
    {"term":"구강 작열감 증후군","category":"치과 질환","short":"입 안이 화끈거리는 만성 통증","detail":"구강 작열감 증후군(BMS)은 혀나 입천장이 화끈거리는 만성 통증 질환입니다. 주로 폐경기 여성에서 발생하며, 스트레스, 영양 결핍 등이 관련됩니다.","tags":["질환"],"synonyms":["BMS"]},
    {"term":"치아 마모증","category":"치과 질환","short":"기계적 마찰로 치아가 닳는 현상","detail":"치아 마모증(Attrition)은 이갈이, 강한 교합력 등으로 치아 표면이 닳아 납작해지는 현상입니다. 심한 경우 상아질이 노출되어 시린 증상이 나타납니다.","tags":["질환"]},
    {"term":"치아 교모증","category":"치과 질환","short":"외부 물질에 의한 치아 마모","detail":"치아 교모증(Abrasion)은 딱딱한 칫솔, 이쑤시개, 파이프 물기 등 외부 물질에 의해 치아가 닳는 현상입니다. 치경부 마모가 대표적입니다.","tags":["질환"]},
    {"term":"낭종","category":"치과 질환","short":"턱뼈 내에 생기는 물혹","detail":"치성 낭종은 치아 관련 조직에서 발생하는 물혹으로, 치근단 낭종, 함치성 낭종, 각화 낭종 등이 있습니다. CT로 진단하며 외과적 제거가 필요합니다.","tags":["질환","외과"],"synonyms":["치성 낭종","Cyst"]},
    {"term":"상악동염","category":"치과 질환","short":"위턱 어금니 부위 부비동 염증","detail":"치성 상악동염은 윗 어금니의 감염이 바로 위에 있는 상악동(부비동)으로 퍼진 상태입니다. 코막힘, 안면통, 악취 등의 증상이 있으며 원인 치아 치료가 필요합니다.","tags":["질환"],"synonyms":["치성 부비동염"]},
    {"term":"삼차신경통","category":"치과 질환","short":"얼굴에 전기 쏘듯 심한 통증","detail":"삼차신경통은 얼굴의 감각을 담당하는 삼차신경에 갑자기 찌르는 듯한 심한 통증이 발생하는 질환입니다. 치통으로 오인하기 쉬워 감별 진단이 중요합니다.","tags":["질환"]},
    {"term":"설암","category":"치과 질환","short":"혀에 발생하는 악성 종양","detail":"설암은 구강암 중 가장 흔한 유형으로, 혀 옆면에 잘 발생합니다. 2주 이상 낫지 않는 궤양, 덩어리, 통증이 있으면 즉시 전문의 진료가 필요합니다.","tags":["질환"]},
    {"term":"골수염","category":"치과 질환","short":"턱뼈에 발생하는 심한 감염","detail":"턱뼈 골수염(Osteomyelitis)은 치아 감염이 뼈로 퍼져 발생하는 심각한 감염입니다. 항생제 치료와 외과적 배농, 때로는 괴사 뼈 제거가 필요합니다.","tags":["질환","외과"]},
    {"term":"구강 점막 화상","category":"치과 질환","short":"뜨거운 음식이나 화학물질에 의한 점막 손상","detail":"구강 화상은 뜨거운 음식, 아스피린 직접 접촉 등으로 점막이 손상된 상태입니다. 대부분 자연 치유되나, 심한 경우 감염 예방 관리가 필요합니다.","tags":["질환"]},
    {"term":"혀 갈라짐","category":"치과 질환","short":"혀 표면에 깊은 주름이 생기는 상태","detail":"열구설(Fissured Tongue)은 혀 표면에 여러 개의 깊은 홈이 생기는 양성 상태입니다. 전 인구의 약 5%에서 나타나며, 음식물이 끼면 불편할 수 있습니다.","tags":["질환"],"synonyms":["열구설"]},
    {"term":"지도설","category":"치과 질환","short":"혀에 지도 모양 반점이 나타나는 상태","detail":"지도설(Geographic Tongue)은 혀 표면의 유두가 부분적으로 탈락하여 지도 모양의 붉은 반점이 나타나는 양성 질환입니다. 통증은 보통 없으나 매운 음식에 민감할 수 있습니다.","tags":["질환"],"synonyms":["Geographic Tongue"]},
    {"term":"수포성 질환","category":"치과 질환","short":"구강 점막에 물집이 생기는 질환군","detail":"천포창, 유천포창 등 자가면역 질환으로 구강 점막에 물집이 생기고 쉽게 벗겨지는 질환입니다. 전신 스테로이드 치료가 필요할 수 있습니다.","tags":["질환"]},
    {"term":"골괴사","category":"치과 질환","short":"턱뼈 조직이 죽는 질환","detail":"약물관련 턱뼈괴사(MRONJ)는 골다공증 치료제(비스포스포네이트) 복용 환자에서 발치 후 뼈가 치유되지 않는 상태입니다. 시술 전 반드시 복용 이력을 알려야 합니다.","tags":["질환"],"synonyms":["MRONJ","비스포스포네이트 관련 골괴사"]},

    # ===== 치료·시술 (추가) =====
    {"term":"근관 재치료","category":"치료·시술","short":"이전 신경치료를 다시 하는 것","detail":"근관 재치료는 기존 신경치료가 실패하여 재감염되었을 때 기존 충전재를 제거하고 다시 세척·소독·충전하는 치료입니다. 미세현미경 사용이 성공률을 높입니다.","tags":["치료"],"link":"/treatments/root-canal"},
    {"term":"의도적 재식술","category":"치료·시술","short":"치아를 뽑았다가 치료 후 다시 심는 시술","detail":"의도적 재식술은 일반 근관치료가 어려운 치아를 발치하여 구강 밖에서 치료한 후 다시 원래 위치에 심는 시술입니다.","tags":["외과"]},
    {"term":"치조골 보존술","category":"치료·시술","short":"발치 후 뼈 흡수를 막는 시술","detail":"발치 후 치조골은 급속히 흡수됩니다. 치조골 보존술(Socket Preservation)은 발치 와에 골이식재를 넣어 뼈 흡수를 최소화하고 향후 임플란트를 위한 뼈를 보존합니다.","tags":["외과"],"link":"/treatments/implant","synonyms":["Socket Preservation"]},
    {"term":"절개 배농","category":"치료·시술","short":"농양을 절개하여 고름을 빼내는 응급 시술","detail":"절개 배농(I&D)은 급성 농양의 고름을 잇몸을 절개하여 배출시키는 응급 처치입니다. 통증과 부종을 즉시 완화하며, 이후 원인 치료가 필요합니다.","tags":["외과"],"synonyms":["I&D"]},
    {"term":"조직 재생 유도술","category":"치료·시술","short":"잇몸뼈 재생을 유도하는 치주 수술","detail":"GTR(Guided Tissue Regeneration)은 차단막과 골이식재를 이용해 치주염으로 파괴된 치조골과 치주인대의 재생을 유도하는 수술 기법입니다.","tags":["외과"],"synonyms":["GTR"]},
    {"term":"치은 이식술","category":"치료·시술","short":"잇몸을 이식하는 수술","detail":"치은 이식술은 잇몸이 퇴축(내려감)된 부위에 입천장 등에서 잇몸 조직을 떼어 이식하는 수술입니다. 시린 증상 해결과 심미 개선에 효과적입니다.","tags":["외과"],"synonyms":["잇몸 이식","FGG","CTG"]},
    {"term":"치관 연장술","category":"치료·시술","short":"잇몸을 낮춰 치아를 더 드러내는 수술","detail":"치관 연장술(Crown Lengthening)은 잇몸과 뼈를 성형하여 치아의 보이는 부분을 늘리는 수술입니다. 거미스마일 개선이나 크라운 제작을 위해 시행합니다.","tags":["외과","심미"]},
    {"term":"치아 재건술","category":"치료·시술","short":"심하게 파손된 치아를 복원하는 치료","detail":"치아 재건술(Core Build-up)은 충치나 파절로 크게 손상된 치아를 레진이나 금속 포스트를 이용해 크라운 장착이 가능하도록 기둥을 세우는 치료입니다.","tags":["치료"],"synonyms":["Core Build-up","코어"]},
    {"term":"포스트","category":"치료·시술","short":"신경치료 후 치아 내부에 세우는 기둥","detail":"포스트(Post)는 신경치료 후 남은 치근 내부에 삽입하는 기둥으로, 약해진 치아를 보강하고 크라운을 지지합니다. 금속, 섬유 강화 레진 등 다양한 재료가 있습니다.","tags":["치료"],"synonyms":["Post","치근 포스트"]},
    {"term":"직접 치수 복조","category":"치료·시술","short":"노출된 신경을 약으로 덮어 보존하는 치료","detail":"직접 치수 복조(Direct Pulp Capping)는 충치 제거 중 신경이 노출되었을 때 MTA 등의 약제로 덮어 신경을 살리는 보존적 치료법입니다.","tags":["치료"],"synonyms":["Pulp Capping"]},
    {"term":"간접 치수 복조","category":"치료·시술","short":"깊은 충치에서 신경 바로 위를 보호하는 치료","detail":"간접 치수 복조는 충치가 신경에 매우 가까울 때, 신경 위에 얇은 상아질을 남기고 보호 재료를 덮는 보존적 치료입니다.","tags":["치료"]},
    {"term":"치주 소파술","category":"치료·시술","short":"잇몸 안쪽 감염 조직을 긁어내는 시술","detail":"치주 소파술(Curettage)은 치주낭 내부의 감염된 연조직과 치석을 제거하는 비수술적 치주 치료입니다. 깊은 치주낭(4~5mm)에 시행합니다.","tags":["치료"],"link":"/treatments/gum","synonyms":["Curettage"]},
    {"term":"치근 활택술","category":"치료·시술","short":"치아 뿌리 표면을 매끄럽게 다듬는 시술","detail":"치근 활택술(Root Planing)은 치근 표면의 독소와 오염물을 제거하고 매끄럽게 다듬어 잇몸이 치아에 다시 부착되도록 돕는 치주 치료입니다.","tags":["치료"],"link":"/treatments/gum","synonyms":["Root Planing"]},
    {"term":"잇몸 절제술","category":"치료·시술","short":"과도하게 자란 잇몸을 잘라내는 시술","detail":"잇몸 절제술(Gingivectomy)은 약물이나 치주염으로 비대해진 잇몸을 레이저나 전기 메스로 절제하는 시술입니다.","tags":["치료","심미"],"synonyms":["Gingivectomy"]},
    {"term":"PRF","category":"치료·시술","short":"자가 혈액에서 추출한 재생 촉진제","detail":"PRF(Platelet Rich Fibrin)는 환자 본인의 혈액을 원심분리하여 얻는 혈소판 농축액입니다. 골이식, 발치 후 치유, 임플란트 수술 시 조직 재생을 촉진합니다.","tags":["외과"],"synonyms":["혈소판 농축액"]},
    {"term":"광중합","category":"치료·시술","short":"LED 빛으로 레진을 굳히는 과정","detail":"광중합(Light Curing)은 LED 또는 할로겐 조사기로 특정 파장의 빛을 쏘아 레진 재료를 화학적으로 경화시키는 과정입니다. 약 20~40초 소요됩니다.","tags":["치료"]},
    {"term":"치아 탈색","category":"치료·시술","short":"신경치료 후 변색된 치아를 밝게 하는 시술","detail":"치아 내부 미백(Walking Bleach)은 신경치료 후 변색된 치아 내부에 미백제를 넣어 색을 밝히는 시술입니다. 1~2주 간격으로 약 교체하며 진행합니다.","tags":["심미"],"synonyms":["Walking Bleach","내부 미백"]},
    {"term":"교정용 탄성체인","category":"치료·시술","short":"교정에서 치아 간격을 줄이는 고무 체인","detail":"탄성 체인(Elastic Chain)은 교정 치료에서 치아 사이 공간을 닫거나 치아를 이동시키기 위해 브라켓에 걸어 사용하는 고무 연결 고리입니다.","tags":["교정"]},
    {"term":"치과 봉합","category":"치료·시술","short":"구강 수술 후 잇몸을 꿰매는 과정","detail":"치과 봉합은 발치, 임플란트, 잇몸 수술 후 절개 부위를 실로 꿰매 치유를 돕는 과정입니다. 흡수성 실은 자연 흡수되고, 비흡수성 실은 7~14일 후 제거합니다.","tags":["외과"]},
    {"term":"지혈 처치","category":"치료·시술","short":"출혈을 멈추게 하는 응급 처치","detail":"치과 시술 후 출혈이 있을 때 거즈를 물고 압박하거나, 지혈제를 적용하여 출혈을 멈추는 처치입니다. 발치 후 2~3시간 거즈 압박이 기본입니다.","tags":["외과"]},
    {"term":"마이크로 임플란트","category":"치료·시술","short":"매우 작은 직경의 교정용 고정 나사","detail":"마이크로 임플란트는 교정 치료에서 치아를 원하는 방향으로 이동시키기 위한 고정원으로 사용되는 작은 티타늄 나사입니다. 직경 1.2~2.0mm 정도입니다.","tags":["교정"]},
    {"term":"고난도 임플란트","category":"치료·시술","short":"뼈 부족 등 어려운 조건의 임플란트","detail":"고난도 임플란트는 심한 골 흡수, 상악동 근접, 신경관 인접 등 난이도가 높은 경우의 임플란트 시술입니다. 3D CT 분석과 풍부한 경험이 필수적입니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"임플란트 재수술","category":"치료·시술","short":"실패한 임플란트를 다시 하는 수술","detail":"임플란트 재수술은 기존 임플란트가 실패(탈락, 감염)했을 때 제거 후 골이식을 거쳐 새로 식립하는 수술입니다. 첫 수술보다 난이도가 높습니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"무절개 임플란트","category":"치료·시술","short":"잇몸을 절개하지 않고 식립하는 임플란트","detail":"무절개(Flapless) 임플란트는 가이드를 이용해 잇몸에 작은 구멍만 뚫어 식립하는 방법입니다. 출혈·부종이 적고 회복이 빠르지만, 뼈 상태가 양호해야 합니다.","tags":["치료"],"link":"/treatments/implant","synonyms":["Flapless"]},
    {"term":"수면 임플란트","category":"치료·시술","short":"수면 진정 상태에서 하는 임플란트","detail":"수면 임플란트는 정맥 진정(수면 마취) 하에 시행하는 임플란트 시술로, 치과 공포증이 있거나 다수 임플란트를 한 번에 시행할 때 적합합니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"원데이 임플란트","category":"치료·시술","short":"당일 발치와 임플란트, 임시치아를 완료하는 시술","detail":"원데이 임플란트는 발치, 임플란트 식립, 임시치아 장착을 하루에 완료하는 시술입니다. 시간과 내원 횟수를 줄여주지만, 뼈 상태 등 조건이 맞아야 합니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"자가치아 이식재","category":"치료·시술","short":"발치한 본인의 치아로 만든 뼈 이식재","detail":"자가치아 이식재는 발치한 치아를 분쇄·멸균 처리하여 골이식재로 사용하는 기술입니다. 자기 조직이라 거부 반응이 없고 골 재생 효과가 우수합니다.","tags":["외과"],"link":"/treatments/implant","synonyms":["AutoBT"]},
    {"term":"잇몸 레이저 치료","category":"치료·시술","short":"레이저로 잇몸 질환을 치료하는 시술","detail":"잇몸 레이저 치료는 다이오드, Er:YAG 등의 레이저를 이용해 잇몸 염증 조직을 제거하고 살균하는 시술입니다. 출혈이 적고 회복이 빠른 장점이 있습니다.","tags":["치료"],"link":"/treatments/gum"},
    {"term":"셀프 라이게이팅 브라켓","category":"치료·시술","short":"와이어를 자동으로 잡아주는 교정 장치","detail":"셀프 라이게이팅(자가결찰) 브라켓은 클립 구조로 와이어를 잡아 별도의 고무링이 필요 없습니다. 마찰이 적어 치아 이동이 빠르고 통증이 적습니다.","tags":["교정"],"link":"/treatments/invisalign","synonyms":["자가결찰 브라켓","데이몬"]},
    {"term":"투명 교정","category":"치료·시술","short":"투명한 플라스틱 장치를 이용한 교정","detail":"투명 교정(Clear Aligner)은 인비절라인, 클리어얼라이너 등 투명 플라스틱 장치로 치아를 이동시키는 교정 방법입니다. 심미적이고 탈착 가능한 장점이 있습니다.","tags":["교정"],"link":"/treatments/invisalign","synonyms":["Clear Aligner"]},
    {"term":"악간 고무줄","category":"치료·시술","short":"위아래 교정 장치를 연결하는 고무줄","detail":"악간 고무줄(Elastic)은 위아래 교정 장치에 걸어 교합 관계를 맞추는 작은 고무줄입니다. 환자가 직접 착용하며 착용 시간이 결과에 큰 영향을 줍니다.","tags":["교정"]},
    {"term":"스트리핑","category":"치료·시술","short":"치아 사이를 미세하게 다듬는 교정 과정","detail":"스트리핑(IPR, Interproximal Reduction)은 치아 사이 법랑질을 0.1~0.5mm 미세하게 다듬어 공간을 만드는 교정 시술입니다. 비발치 교정 시 많이 사용됩니다.","tags":["교정"],"synonyms":["IPR"]},
    {"term":"구강 내 촬영","category":"치료·시술","short":"치아 내부를 가까이서 촬영하는 엑스레이","detail":"구강 내 촬영은 필름을 입 안에 넣어 1~3개 치아를 정밀하게 촬영하는 방법입니다. 충치 깊이, 뿌리 상태, 치주 골 수준 확인에 사용됩니다.","tags":["치료"]},

    # ===== 치과 재료 (추가) =====
    {"term":"PMMA","category":"치과 재료","short":"임시 보철물 제작용 아크릴 재료","detail":"PMMA(폴리메틸메타크릴레이트)는 임시 크라운, 틀니, 교정 장치 등에 사용되는 아크릴 수지입니다. 가공이 쉽고 저렴하나 장기 사용에는 부적합합니다.","tags":["재료"]},
    {"term":"인상재","category":"치과 재료","short":"치아 본을 뜨는 재료","detail":"인상재는 실리콘(PVS), 알지네이트, 폴리에테르 등 치아와 잇몸의 형태를 정밀하게 본뜨는 재료입니다. 디지털 스캐너가 점차 대체하고 있습니다.","tags":["재료"],"synonyms":["실리콘 인상재","알지네이트"]},
    {"term":"치과용 시멘트","category":"치과 재료","short":"크라운, 브릿지를 고정하는 접착 재료","detail":"치과용 시멘트는 크라운, 인레이, 브릿지 등을 치아에 접착하는 재료입니다. 글라스 아이오노머, 레진 시멘트, 아연 포스페이트 시멘트 등이 있습니다.","tags":["재료"]},
    {"term":"본딩제","category":"치과 재료","short":"레진을 치아에 접착시키는 액체","detail":"본딩제(Bonding Agent)는 레진 수복물과 치아 표면을 화학적으로 연결하는 접착 매개체입니다. 에칭 후 도포하여 미세한 결합을 형성합니다.","tags":["재료"],"synonyms":["Bonding Agent"]},
    {"term":"석고","category":"치과 재료","short":"치아 모형 제작용 재료","detail":"치과용 석고(Dental Stone)는 인상체(본)에 부어 치아 모형을 만드는 재료입니다. 경도에 따라 보통 석고, 경질 석고, 초경질 석고로 분류됩니다.","tags":["재료"],"synonyms":["Dental Stone"]},
    {"term":"왁스","category":"치과 재료","short":"보철물 형태를 만드는 모형 재료","detail":"치과용 왁스는 크라운, 틀니 등의 형태를 미리 만들어보는 모형(왁스업)에 사용됩니다. 정밀한 주조를 위한 로스트 왁스 기법에도 사용됩니다.","tags":["재료"]},
    {"term":"구타페르카","category":"치과 재료","short":"신경치료 후 근관을 채우는 고무 재료","detail":"구타페르카(Gutta Percha)는 천연 고무로 만든 원추형 재료로, 신경치료 후 비어있는 근관을 밀봉하는 충전재입니다.","tags":["재료"],"synonyms":["Gutta Percha","GP"]},
    {"term":"하이브리드 세라믹","category":"치과 재료","short":"레진과 세라믹의 장점을 결합한 재료","detail":"하이브리드 세라믹은 세라믹의 심미성과 레진의 유연성을 결합한 CAD/CAM용 보철 재료입니다. 대합치 마모가 적고, 수리가 가능한 장점이 있습니다.","tags":["재료"],"synonyms":["CAD/CAM 블록"]},
    {"term":"임시 시멘트","category":"치과 재료","short":"임시 보철물을 고정하는 약한 접착제","detail":"임시 시멘트(Temporary Cement)는 임시 크라운 등을 일시적으로 고정하되, 추후 쉽게 제거할 수 있도록 접착력이 약한 시멘트입니다.","tags":["재료"]},
    {"term":"섬유 강화 복합레진","category":"치과 재료","short":"유리섬유로 강도를 높인 레진","detail":"섬유 강화 복합레진(FRC)은 유리섬유를 레진에 포함시켜 강도를 높인 재료입니다. 치주 스플린트, 임시 브릿지, 포스트 등에 사용됩니다.","tags":["재료"],"synonyms":["FRC"]},
    {"term":"불소 바니시","category":"치과 재료","short":"고농도 불소를 치아에 바르는 도포제","detail":"불소 바니시(Fluoride Varnish)는 고농도 불소를 치아에 얇게 코팅하여 충치를 예방하는 전문 도포제입니다. 바른 후 4~6시간 동안 음식 섭취를 피합니다.","tags":["재료","소아"]},
    {"term":"네오","category":"치과 재료","short":"글로벌 임플란트 브랜드","detail":"네오(Neobiotech)는 한국의 임플란트 브랜드로, IS-II, IS-III 등의 라인업이 있습니다. 가성비가 좋고 국내외에서 널리 사용됩니다.","tags":["재료"],"link":"/treatments/implant","synonyms":["Neobiotech","네오바이오텍"]},

    # ===== 장비·기술 (추가) =====
    {"term":"디지털 워크플로우","category":"장비·기술","short":"구강 스캔부터 보철 제작까지 디지털화한 과정","detail":"디지털 워크플로우는 구강 스캔→CAD 설계→CAM/3D프린팅 제작까지 전 과정을 디지털로 수행하는 시스템입니다. 정밀도와 효율성이 크게 향상됩니다.","tags":["장비"]},
    {"term":"Er:YAG 레이저","category":"장비·기술","short":"치아와 뼈를 절삭할 수 있는 치과 레이저","detail":"Er:YAG 레이저는 물 분자를 이용해 치아, 뼈, 연조직을 절삭하는 레이저입니다. 진동과 소음이 적어 환자 편안함이 높고 감염 조직 제거에 효과적입니다.","tags":["장비"]},
    {"term":"다이오드 레이저","category":"장비·기술","short":"연조직 치료에 특화된 레이저","detail":"다이오드 레이저는 잇몸 절제, 잇몸 성형, 구내염 치료, 미백 촉진 등 연조직 시술에 주로 사용되는 반도체 레이저입니다.","tags":["장비"]},
    {"term":"피에조 서저리","category":"장비·기술","short":"초음파로 뼈를 정밀하게 자르는 장비","detail":"피에조 서저리(Piezosurgery)는 초음파 진동으로 뼈를 정밀하게 절삭하는 장비입니다. 신경이나 연조직 손상 없이 뼈만 절삭하여 안전합니다.","tags":["장비"],"synonyms":["Piezosurgery"]},
    {"term":"LED 광중합기","category":"장비·기술","short":"레진을 경화시키는 LED 조사기","detail":"LED 광중합기는 특정 파장(470nm)의 빛을 방출하여 복합레진, 시멘트 등 광경화 재료를 굳히는 치과 장비입니다. 20~40초로 빠른 경화가 가능합니다.","tags":["장비"]},
    {"term":"전기근관장 측정기","category":"장비·기술","short":"치아 뿌리 길이를 전기적으로 측정하는 기기","detail":"전기근관장 측정기(Apex Locator)는 신경치료 시 치아 뿌리의 정확한 길이를 전기 저항으로 측정하는 장비입니다. 방사선 촬영 횟수를 줄여줍니다.","tags":["장비"],"synonyms":["Apex Locator"]},
    {"term":"니켈타이타늄 파일","category":"장비·기술","short":"유연한 신경치료용 기구","detail":"NiTi 파일은 니켈-티타늄 합금으로 만든 유연한 근관치료 기구입니다. 초탄성이 있어 휘어진 근관에서도 파절 없이 안전하게 치료할 수 있습니다.","tags":["장비"],"synonyms":["NiTi 파일","로타리 파일"]},
    {"term":"회전 기구","category":"장비·기술","short":"전동으로 회전하는 근관치료 기구","detail":"회전 기구(Rotary File)는 전동 핸드피스에 장착하여 사용하는 근관치료 기구입니다. 수동 파일보다 빠르고 정확하게 근관을 성형합니다.","tags":["장비"]},
    {"term":"핸드피스","category":"장비·기술","short":"치과 드릴(치아 깎는 기구)","detail":"핸드피스는 치아를 삭제하는 치과 드릴입니다. 고속(터빈, 30~40만 rpm)과 저속(콘트라앵글)으로 나뉘며, 충치 제거, 보철 삭제 등에 사용됩니다.","tags":["장비"],"synonyms":["치과 드릴","터빈"]},
    {"term":"석션","category":"장비·기술","short":"구강 내 물과 타액을 흡입하는 기구","detail":"석션(Suction)은 치과 치료 중 물, 타액, 혈액 등을 흡입하여 시야를 확보하는 기구입니다. 고속 석션과 저속 석션이 있습니다.","tags":["장비"]},
    {"term":"교정용 와이어","category":"장비·기술","short":"치아에 힘을 전달하는 교정 철사","detail":"교정용 와이어(Archwire)는 브라켓에 끼워 치아를 이동시키는 금속선입니다. NiTi(초기 배열), 스테인리스 스틸(마무리), TMA 등 단계별로 다른 와이어를 사용합니다.","tags":["장비","교정"]},
    {"term":"밀링 머신","category":"장비·기술","short":"보철물을 깎아 만드는 CAM 장비","detail":"치과용 밀링 머신은 지르코니아, 세라믹, 왁스 블록을 CAD 설계대로 깎아 크라운, 인레이 등 보철물을 제작하는 장비입니다.","tags":["장비"]},
    {"term":"치과용 현미경","category":"장비·기술","short":"최대 25배 확대하여 정밀 시술하는 장비","detail":"치과용 현미경(마이크로스코프)은 근관치료, 미세 수술 등에서 육안으로 불가능한 정밀 시술을 가능하게 합니다. 빛과 확대율 조절이 가능합니다.","tags":["장비"],"synonyms":["마이크로스코프"]},
    {"term":"방사선 방어","category":"장비·기술","short":"엑스레이 촬영 시 방사선 차단 장비","detail":"납 조끼(Lead Apron), 갑상선 보호대(Thyroid Shield) 등 방사선 촬영 시 불필요한 부위의 방사선 노출을 차단하는 보호 장비입니다.","tags":["장비"]},
    {"term":"디지털 센서","category":"장비·기술","short":"엑스레이를 디지털로 촬영하는 장비","detail":"디지털 센서는 기존 필름 대신 전자 센서로 방사선을 감지하여 즉시 컴퓨터에 영상을 표시합니다. 방사선량이 기존 대비 50~80% 감소합니다.","tags":["장비"]},

    # ===== 교정 (추가) =====
    {"term":"세파로 분석","category":"교정","short":"측면 두부 방사선을 분석하여 교정 진단","detail":"세파로 분석(Cephalometric Analysis)은 머리 옆면 방사선 사진에서 기준점을 측정하여 턱뼈, 치아 관계를 분석하는 교정 진단 방법입니다.","tags":["교정"],"synonyms":["Cephalometric","세팔로"]},
    {"term":"교정 왁스","category":"교정","short":"브라켓의 자극을 줄이는 보호 왁스","detail":"교정 왁스는 브라켓이나 와이어가 볼이나 입술을 찌를 때 덮어 자극을 줄이는 밀랍 형태의 보호재입니다.","tags":["교정"]},
    {"term":"파워체인","category":"교정","short":"치아 간격을 빠르게 닫는 교정 도구","detail":"파워체인(Power Chain)은 연속된 고무 링으로, 브라켓에 걸어 치아 사이 공간을 빠르게 닫는 데 사용합니다. 2~4주마다 교체합니다.","tags":["교정"]},
    {"term":"확장 장치","category":"교정","short":"위턱을 넓히는 교정 장치","detail":"구개 확장 장치(RPE, Rapid Palatal Expander)는 위턱이 좁은 경우 구개를 넓히는 장치입니다. 성장기 아이에게 효과적이며, 하루 1~2회 나사를 돌립니다.","tags":["교정","소아"],"synonyms":["RPE","급속 구개 확장"]},
    {"term":"헤드기어","category":"교정","short":"턱 성장을 조절하는 교정용 외장 장치","detail":"헤드기어는 머리에 착용하여 위턱 성장을 억제하거나 어금니를 뒤로 이동시키는 교정 장치입니다. 주로 성장기 아동에게 취침 시 착용합니다.","tags":["교정","소아"]},
    {"term":"턱 성장 장치","category":"교정","short":"아이의 턱뼈 성장을 유도하는 교정 장치","detail":"기능성 장치(Functional Appliance)는 아래턱이 작은 아이에서 턱 성장을 전방 유도하는 장치입니다. 트윈블록, 바이오네이터 등이 있습니다.","tags":["교정","소아"],"synonyms":["기능성 장치","트윈블록"]},
    {"term":"교정 밴드","category":"교정","short":"어금니에 끼우는 금속 링","detail":"교정 밴드(Band)는 어금니에 끼우는 금속 링으로, 교정 튜브나 확장 장치를 고정하는 데 사용됩니다.","tags":["교정"]},
    {"term":"어태치먼트","category":"교정","short":"투명 교정 시 치아에 붙이는 작은 돌기","detail":"어태치먼트(Attachment)는 인비절라인 등 투명 교정 시 치아에 레진으로 만든 작은 돌기를 붙여 장치가 치아에 힘을 효과적으로 전달하도록 돕는 장치입니다.","tags":["교정"],"link":"/treatments/invisalign"},
    {"term":"교정 고무줄","category":"교정","short":"치아 이동을 돕는 다양한 탄성 재료","detail":"교정용 고무줄은 분리 고무(어금니 사이 벌림), 악간 고무줄(위아래 연결), O-ring(와이어 고정) 등 다양한 종류가 있으며 각각 역할이 다릅니다.","tags":["교정"]},
    {"term":"ClinCheck","category":"교정","short":"인비절라인의 3D 치료 시뮬레이션","detail":"ClinCheck은 인비절라인 교정 전 3D 소프트웨어로 치아 이동 과정과 최종 결과를 미리 시뮬레이션하는 프로그램입니다. 치료 전 예상 결과를 확인할 수 있습니다.","tags":["교정"],"link":"/treatments/invisalign"},

    # ===== 구강 관리 (추가) =====
    {"term":"바스법","category":"구강 관리","short":"치과에서 가장 권장하는 칫솔질 방법","detail":"바스법(Bass Method)은 칫솔모를 잇몸 경계에 45도 각도로 대고 짧은 진동을 주는 칫솔질 방법입니다. 잇몸 속 치태를 효과적으로 제거합니다.","tags":["예방"],"synonyms":["Bass Method"]},
    {"term":"치약","category":"구강 관리","short":"칫솔질 시 사용하는 구강 세정제","detail":"치약은 연마제, 불소, 계면활성제 등을 포함하며 플라크 제거와 충치 예방을 돕습니다. 불소 1,000~1,500ppm 함유 치약이 권장됩니다.","tags":["예방"]},
    {"term":"칫솔 선택","category":"구강 관리","short":"올바른 칫솔 고르는 방법","detail":"부드러운 모(Soft)의 작은 머리 칫솔이 잇몸 손상을 최소화하면서 효과적으로 플라크를 제거합니다. 3개월마다 또는 모가 벌어지면 교체합니다.","tags":["예방"]},
    {"term":"치아에 좋은 음식","category":"구강 관리","short":"치아 건강을 돕는 식이요법","detail":"칼슘(우유, 치즈), 섬유소(채소, 과일), 녹차(카테킨)는 치아 건강에 좋습니다. 반면 탄산음료, 과자, 끈적한 사탕은 충치 위험을 높입니다.","tags":["예방"]},
    {"term":"치아에 나쁜 습관","category":"구강 관리","short":"치아를 손상시키는 일상 습관","detail":"얼음 깨물기, 손톱 물기, 이로 병뚜껑 따기, 한쪽으로만 씹기, 이쑤시개 습관적 사용 등은 치아 파절, 마모, 턱관절 장애를 유발할 수 있습니다.","tags":["예방"]},
    {"term":"치과 정기 검진","category":"구강 관리","short":"6개월마다 치과를 방문하는 예방 습관","detail":"정기 검진은 충치, 잇몸 질환, 구강암 등을 조기 발견하는 핵심 예방법입니다. 6개월~1년 간격으로 스케일링과 함께 받는 것이 권장됩니다.","tags":["예방"]},
    {"term":"임플란트 관리","category":"구강 관리","short":"임플란트를 오래 쓰기 위한 관리법","detail":"임플란트는 자연치아보다 치주 관리가 더 중요합니다. 치간 칫솔, 워터 플로서로 임플란트 주위를 매일 청소하고, 3~6개월마다 정기 검진을 받아야 합니다.","tags":["예방"],"link":"/treatments/implant"},
    {"term":"교정 중 관리","category":"구강 관리","short":"교정 장치 착용 중 구강 관리법","detail":"교정 중에는 브라켓 주위로 음식물이 잘 끼어 충치 위험이 높아집니다. 교정 전용 칫솔, 치간 칫솔, 워터 플로서를 사용하고, 딱딱한 음식을 피해야 합니다.","tags":["예방","교정"]},
    {"term":"틀니 관리","category":"구강 관리","short":"틀니의 올바른 세척과 보관법","detail":"틀니는 식후 흐르는 물에 전용 솔로 세척하고, 취침 시에는 물이나 틀니 세정액에 담가 보관합니다. 뜨거운 물은 변형을 일으키므로 피해야 합니다.","tags":["예방"]},
    {"term":"금연과 구강건강","category":"구강 관리","short":"흡연이 구강에 미치는 악영향","detail":"흡연은 치주 질환 위험을 2~6배 높이고, 임플란트 실패율 증가, 잇몸 치유 지연, 구강암 위험 증가, 치아 변색을 유발합니다. 금연이 가장 효과적인 예방법입니다.","tags":["예방"]},
    {"term":"당뇨와 구강건강","category":"구강 관리","short":"당뇨병이 치아와 잇몸에 미치는 영향","detail":"당뇨 환자는 면역력 저하와 혈관 변화로 치주염 위험이 3배 높습니다. 혈당 관리와 더 자주 치과를 방문하여 잇몸 상태를 점검해야 합니다.","tags":["예방"]},
    {"term":"임산부 구강 관리","category":"구강 관리","short":"임신 중 치아와 잇몸 관리법","detail":"임신 호르몬 변화로 잇몸 출혈과 부종(임신성 치은염)이 흔합니다. 안정기(4~6개월)에 스케일링과 필수 치료를 받고, 입덧 후에는 물로 헹궈 산을 중화합니다.","tags":["예방"]},
    {"term":"노인 구강 관리","category":"구강 관리","short":"고령자를 위한 특별한 구강 관리","detail":"노인은 구강 건조증, 치근 충치, 잇몸 퇴축이 증가합니다. 불소 치약, 인공 타액, 전동 칫솔 사용이 도움되며, 최소 6개월마다 정기 검진이 필요합니다.","tags":["예방"]},
    {"term":"스포츠 치과","category":"구강 관리","short":"운동 중 치아 보호와 손상 대처법","detail":"격투기, 농구, 축구 등 접촉 스포츠에서 맞춤형 마우스가드 착용으로 치아 파절을 90% 예방할 수 있습니다. 치아가 빠지면 우유에 담아 30분 내 치과를 방문합니다.","tags":["예방"]},

    # ===== 소아 치과 (추가) =====
    {"term":"치아 맹출 순서","category":"소아 치과","short":"치아가 나오는 순서와 시기","detail":"유치는 아래 앞니(6~10개월)부터 시작하여 만 3세에 20개가 완성됩니다. 영구치는 제1대구치(6세)부터 교환되기 시작합니다.","tags":["소아"],"link":"/treatments/pediatric"},
    {"term":"과잉치 발치","category":"소아 치과","short":"여분의 치아를 제거하는 시술","detail":"정중과잉치 등 여분의 치아가 영구치 맹출을 방해하면 CT 촬영 후 발치합니다. 대부분 국소마취로 시행하며, 필요시 수면마취를 병행합니다.","tags":["소아"],"link":"/treatments/pediatric"},
    {"term":"치아 외상 대처","category":"소아 치과","short":"아이 치아가 다쳤을 때 응급 대처법","detail":"영구치가 완전히 빠지면 뿌리를 만지지 않고 우유나 식염수에 넣어 30분 이내에 치과를 방문합니다. 유치는 재식하지 않습니다.","tags":["소아"],"link":"/treatments/pediatric"},
    {"term":"구호흡","category":"소아 치과","short":"코가 아닌 입으로 숨쉬는 습관","detail":"구호흡(Mouth Breathing)은 아데노이드 비대, 비염 등으로 입으로 숨쉬는 습관입니다. 얼굴형 변형, 치열 불규칙, 잇몸 건조 등을 유발하므로 조기 교정이 필요합니다.","tags":["소아"],"synonyms":["Mouth Breathing"]},
    {"term":"손가락 빨기","category":"소아 치과","short":"영유아의 손가락 흡입 습관","detail":"3세 이전 손가락 빨기는 정상 발달 과정이나, 4세 이후 지속되면 앞니 돌출, 개방교합 등 치열 문제를 유발합니다. 행동 수정법으로 교정합니다.","tags":["소아"],"link":"/treatments/pediatric"},
    {"term":"혀 내밀기","category":"소아 치과","short":"삼킬 때 혀를 앞으로 미는 습관","detail":"혀 내밀기(Tongue Thrust)는 음식을 삼킬 때 혀가 앞니 사이로 밀려나오는 비정상 습관입니다. 개방교합과 앞니 돌출의 원인이 됩니다.","tags":["소아"],"synonyms":["Tongue Thrust"]},
    {"term":"소아 보호대","category":"소아 치과","short":"활동적인 아이를 위한 치아 보호 장치","detail":"소아 보호대는 운동이나 놀이 중 치아 손상을 예방하는 맞춤형 마우스가드입니다. 특히 교정 중인 아이에게 권장됩니다.","tags":["소아"]},
    {"term":"유치 신경치료","category":"소아 치과","short":"유치의 감염된 신경을 치료하는 시술","detail":"유치 신경치료(생활치수절단술)는 감염이 치관부 신경에 국한된 경우 건강한 뿌리 신경은 보존하고 감염 부분만 제거하는 시술입니다.","tags":["소아"],"link":"/treatments/pediatric","synonyms":["생활치수절단술"]},
    {"term":"첫 치과 방문","category":"소아 치과","short":"아이의 첫 치과 방문 시기와 방법","detail":"첫 치아가 나온 후 또는 만 1세 이전에 첫 치과 방문을 권장합니다. 치아 상태 점검, 구강 관리 교육, 불소 도포 등을 받을 수 있습니다.","tags":["소아"],"link":"/treatments/pediatric"},

    # ===== 보험·비용 (추가) =====
    {"term":"치과 의료급여","category":"보험·비용","short":"저소득층을 위한 치과 진료 지원","detail":"의료급여 수급자는 치과 진료 시 본인부담금이 면제되거나 경감됩니다. 스케일링, 임플란트(65세 이상), 틀니 등에 적용됩니다.","tags":["보험"]},
    {"term":"실비보험 치과 적용","category":"보험·비용","short":"실손의료보험의 치과 보장 범위","detail":"실비보험은 급여 치료 본인부담금을 보장하며, 비급여 특약이 있으면 치료 목적의 크라운, 신경치료 비용도 일부 보장됩니다. 보험사마다 조건이 다릅니다.","tags":["보험"]},
    {"term":"치과 비급여 가격 공개","category":"보험·비용","short":"비급여 항목 가격 공개 제도","detail":"2018년부터 모든 의료기관은 비급여 치료 항목의 가격을 홈페이지나 건강보험심사평가원에 공개해야 합니다. 비교 후 합리적인 선택이 가능합니다.","tags":["보험"],"link":"/pricing"},
    {"term":"어린이 치과 보험","category":"보험·비용","short":"만 12세 이하 아동을 위한 치과 보험 혜택","detail":"만 12세 이하 아동은 충치 예방을 위한 실란트(치아 홈 메우기)에 건강보험이 적용됩니다. 연 1회 스케일링(만 19세 이상)과 별개입니다.","tags":["보험","소아"]},
    {"term":"치과 카드 할부","category":"보험·비용","short":"고액 치과 치료비 분할 납부 방법","detail":"임플란트, 교정 등 고액 치료는 신용카드 무이자 할부, 병원 자체 분납 프로그램 등을 이용할 수 있습니다. 상담 시 결제 방법을 미리 문의하세요.","tags":["보험"],"link":"/pricing"},
    {"term":"국가 무료 검진","category":"보험·비용","short":"국가에서 제공하는 무료 구강 검진","detail":"영유아(18~65개월) 구강 검진, 학교 구강 검진, 국가 건강검진(생애전환기) 등 국가에서 제공하는 무료 구강 검진 제도가 있습니다.","tags":["보험"]},
    {"term":"비용 상담","category":"보험·비용","short":"치과 치료 비용에 대한 사전 상담","detail":"치료 전 비용 상담을 통해 예상 비용, 보험 적용 여부, 분납 가능 여부를 확인할 수 있습니다. 투명한 비용 안내는 환자 신뢰의 기본입니다.","tags":["보험"],"link":"/reservation"},

    # ===== 임플란트 (추가) =====
    {"term":"임플란트 수명","category":"임플란트","short":"임플란트의 예상 사용 기간","detail":"잘 관리된 임플란트는 20년 이상, 평생 사용도 가능합니다. 10년 생존율은 약 95%이며, 정기 검진과 구강 위생 관리가 수명을 결정합니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"임플란트 통증","category":"임플란트","short":"임플란트 시술 중·후 통증 정도","detail":"임플란트 시술은 국소마취 하에 진행되어 시술 중 통증은 거의 없습니다. 시술 후 2~3일간 진통제로 관리 가능한 수준이며, 대부분 1주 내 호전됩니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"임플란트 보증","category":"임플란트","short":"임플란트 제품 및 시술 보증 제도","detail":"대부분의 프리미엄 임플란트 제조사는 10년~평생 제품 보증을 제공합니다. 병원별로 시술 보증 기간과 조건이 다르므로 사전에 확인이 필요합니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"골유착 기간","category":"임플란트","short":"임플란트가 뼈와 붙는 데 걸리는 시간","detail":"골유착 기간은 하악 약 2~3개월, 상악 약 3~6개월입니다. SLActive 표면 처리 등 최신 기술은 골유착 기간을 크게 단축시킵니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"임플란트 식이 주의","category":"임플란트","short":"임플란트 시술 후 음식 주의사항","detail":"시술 후 2주간은 부드러운 음식 위주로 식사하고, 시술 부위로 씹지 않습니다. 최종 보철 완성 전까지 딱딱하거나 끈적한 음식을 피합니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"디지털 임플란트","category":"임플란트","short":"3D 디지털 기술을 활용한 정밀 임플란트","detail":"디지털 임플란트는 CT+구강 스캔으로 가상 수술을 미리 설계하고, 3D 프린팅 가이드를 이용해 계획된 위치에 정확히 식립하는 최첨단 방식입니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"쇼트 임플란트","category":"임플란트","short":"길이가 짧은 특수 임플란트","detail":"쇼트 임플란트(6~8mm)는 뼈 높이가 부족한 환자에서 골이식 없이도 식립 가능한 짧은 임플란트입니다. 수술 범위와 회복 기간을 줄여줍니다.","tags":["치료"],"link":"/treatments/implant"},
    {"term":"자이고마 임플란트","category":"임플란트","short":"광대뼈에 고정하는 특수 임플란트","detail":"자이고마 임플란트(Zygomatic Implant)는 상악골 골 흡수가 극심한 경우 광대뼈(관골)에 긴 임플란트를 고정하는 특수 방법입니다.","tags":["치료"],"synonyms":["Zygomatic Implant"]},
    {"term":"임플란트 유지보수","category":"임플란트","short":"임플란트의 정기적 관리와 부품 교체","detail":"임플란트는 6개월~1년마다 방사선 촬영, 교합 검사, 전문 세척을 받아야 합니다. 나사 풀림, 보철 마모 시 부품 교체가 필요합니다.","tags":["치료"],"link":"/treatments/implant"},

    # ===== 전문 용어 (추가) =====
    {"term":"프로빙","category":"전문 용어","short":"잇몸 깊이를 측정하는 검사","detail":"프로빙(Probing)은 눈금이 있는 가느다란 기구(프로브)를 치아와 잇몸 사이에 넣어 치주낭 깊이를 측정하는 검사입니다. 3mm 이하가 정상입니다.","tags":["기타"],"synonyms":["Probing"]},
    {"term":"치료 계획","category":"전문 용어","short":"종합적인 치과 치료 순서와 방법 설계","detail":"치료 계획(Treatment Plan)은 검사 결과를 바탕으로 어떤 치료를 어떤 순서로 할지 종합적으로 설계하는 것입니다. 환자와 충분한 상의 후 결정합니다.","tags":["기타"]},
    {"term":"주소","category":"전문 용어","short":"환자가 치과를 방문한 주된 이유","detail":"주소(Chief Complaint)는 환자가 가장 불편해하는 증상, 즉 치과를 찾게 된 가장 큰 이유입니다. 정확한 주소 파악이 진단의 시작입니다.","tags":["기타"],"synonyms":["Chief Complaint"]},
    {"term":"예후","category":"전문 용어","short":"치료 후 예상되는 결과","detail":"예후(Prognosis)는 치료 후 해당 치아나 시술이 얼마나 오래, 잘 유지될지 예측하는 것입니다. 양호, 보통, 불량, 절망적 등으로 분류합니다.","tags":["기타"]},
    {"term":"적응증","category":"전문 용어","short":"특정 치료가 적합한 상태나 조건","detail":"적응증(Indication)은 어떤 치료를 적용할 수 있는 의학적 조건입니다. 금기증(Contraindication)은 반대로 치료를 하면 안 되는 조건입니다.","tags":["기타"]},
    {"term":"금기증","category":"전문 용어","short":"특정 치료를 하면 안 되는 상태","detail":"금기증은 혈액 희석제 복용(발치 주의), 비스포스포네이트 복용(발치 후 골괴사 위험), 조절 안 되는 당뇨(감염 위험) 등 시술 전 확인이 필요한 상태입니다.","tags":["기타"]},
    {"term":"합병증","category":"전문 용어","short":"치료 후 발생할 수 있는 부작용","detail":"치과 합병증은 신경 손상(하치조신경 마비), 상악동 천공, 감염, 출혈 등이 있습니다. 발생 확률은 낮으나 사전 설명과 동의가 필수적입니다.","tags":["기타"]},
    {"term":"전달 마취","category":"전문 용어","short":"신경줄기를 차단하는 마취 방법","detail":"전달 마취(Block Anesthesia)는 하악 어금니 치료 시 하치조신경을 차단하여 한쪽 아래턱 전체를 마취하는 방법입니다. 침윤 마취보다 넓은 범위를 마취합니다.","tags":["기타"],"synonyms":["Block Anesthesia"]},
    {"term":"침윤 마취","category":"전문 용어","short":"치료 부위 주변에 직접 놓는 마취","detail":"침윤 마취(Infiltration)는 치료할 치아 주변 잇몸에 직접 마취제를 주사하는 가장 일반적인 마취 방법입니다. 1~2시간 정도 지속됩니다.","tags":["기타"],"synonyms":["Infiltration"]},
    {"term":"표면 마취","category":"전문 용어","short":"주사 전 잇몸에 바르는 마취 젤","detail":"표면 마취(Topical Anesthesia)는 주사 바늘의 찌르는 통증을 줄이기 위해 잇몸에 먼저 바르는 마취 연고입니다. 1~2분 후 효과가 나타납니다.","tags":["기타"]},
    {"term":"하치조신경","category":"전문 용어","short":"아래턱의 감각을 담당하는 주요 신경","detail":"하치조신경(Inferior Alveolar Nerve)은 아래 치아와 아래턱 감각을 담당합니다. 사랑니 발치, 임플란트 시 이 신경 손상을 주의해야 합니다.","tags":["기타"],"synonyms":["IAN"]},
    {"term":"발치 후 주의사항","category":"전문 용어","short":"발치 후 지켜야 할 관리 사항","detail":"발치 후 2시간 거즈 물기, 24시간 음주·흡연·격한 운동 금지, 빨대 사용 금지, 부드러운 음식, 시술 부위 양치 주의 등을 지켜야 합니다.","tags":["기타"]},
    {"term":"치과 응급 상황","category":"전문 용어","short":"즉시 치과 방문이 필요한 긴급 상황","detail":"심한 치통, 치아 탈구, 안면 부종, 조절 안 되는 출혈, 턱 골절 의심 등은 즉시 치과 방문이 필요한 응급 상황입니다.","tags":["기타"]},
    {"term":"치과 기록","category":"전문 용어","short":"진료 내용을 기록하는 의무 문서","detail":"치과 기록(Dental Chart)은 환자의 치아 상태, 진료 내용, 처방 등을 기록하는 법적 의무 문서입니다. 디지털 차트로 전환이 진행 중입니다.","tags":["기타"],"synonyms":["Dental Chart"]},
    {"term":"방사선 안전","category":"전문 용어","short":"치과 엑스레이의 방사선 안전 수준","detail":"치과 파노라마 1장의 방사선량(약 0.01mSv)은 비행기 1시간 탑승과 비슷한 수준입니다. 디지털 장비는 기존 대비 방사선량이 50~80% 감소했습니다.","tags":["기타"]},
    {"term":"약물 상호작용","category":"전문 용어","short":"복용 중인 약과 치과 치료의 관계","detail":"혈액 희석제(와파린, 아스피린), 골다공증 약(비스포스포네이트), 당뇨약 등은 치과 시술에 영향을 줍니다. 복용 중인 약을 반드시 사전에 알려야 합니다.","tags":["기타"]},
    {"term":"의료법","category":"전문 용어","short":"의료 행위와 의료기관을 규율하는 법률","detail":"의료법은 의료인의 자격, 의료기관 개설, 의료광고, 진료기록 관리 등을 규정하는 법률입니다. 치과의사도 이 법률을 준수해야 합니다.","tags":["기타"]},
    {"term":"감염 관리","category":"전문 용어","short":"환자와 의료진을 보호하는 위생 관리 체계","detail":"치과 감염 관리는 기구 멸균, 글러브·마스크 착용, 표면 소독, 1회용품 사용, 에어샤워 등을 포함합니다. 서울비디치과는 대학병원급 감염관리 시스템을 운영합니다.","tags":["기타"]},
    {"term":"진정 치료","category":"전문 용어","short":"약물로 불안감을 줄이는 치료 방법","detail":"진정 치료는 흡입 진정(웃음가스), 경구 진정(약물 복용), 정맥 진정(수면치료)으로 나뉩니다. 의식은 유지되나 불안감이 크게 줄어들어 편안한 치료가 가능합니다.","tags":["기타"]},
    {"term":"보존적 치료","category":"전문 용어","short":"치아를 최대한 보존하는 치료 철학","detail":"보존적 치료는 가능한 한 치아를 살리고 최소한만 삭제하는 치료 방향입니다. 발치보다는 신경치료, 전체 삭제보다는 부분 수복을 우선합니다.","tags":["기타"]},
    {"term":"치과 전문의 제도","category":"전문 용어","short":"한국의 치과 전문의 분류 체계","detail":"한국 치의학 전문의는 9개 분야: 보존과, 보철과, 치주과, 교정과, 소아치과, 구강외과, 구강내과, 영상치의학과, 예방치과. 각 4년간의 수련 과정을 이수합니다.","tags":["기타"]},

    # ===== 추가 치료·시술 =====
    {"term":"레진 인레이","category":"치료·시술","short":"레진 재료로 맞춤 제작하는 간접 수복물","detail":"레진 인레이는 복합레진으로 기공소에서 제작하는 간접 수복물입니다. 금이나 세라믹보다 저렴하면서 직접 레진보다 내구성이 좋습니다.","tags":["치료"],"link":"/treatments/inlay"},
    {"term":"세라믹 인레이","category":"치료·시술","short":"도자기 재료로 맞춤 제작하는 간접 수복물","detail":"세라믹 인레이(포세린 인레이)는 도자기로 제작하여 자연치아와 색상이 거의 동일한 고급 수복물입니다. 변색이 없고 내구성이 우수합니다.","tags":["치료"],"link":"/treatments/inlay"},
    {"term":"골드 인레이","category":"치료·시술","short":"금으로 맞춤 제작하는 간접 수복물","detail":"골드 인레이는 금합금으로 제작한 간접 수복물로, 생체적합성이 우수하고 치아와 마모도가 비슷하여 대합치를 보호합니다. 어금니에 적합합니다.","tags":["치료"],"link":"/treatments/inlay"},
    {"term":"지르코니아 크라운","category":"치료·시술","short":"고강도 세라믹으로 만든 치아 캡","detail":"지르코니아 크라운은 인공 다이아몬드 계열의 세라믹으로 강도와 심미성이 모두 우수합니다. 현재 가장 많이 사용되는 프리미엄 크라운 재료입니다.","tags":["치료"],"link":"/treatments/crown"},
    {"term":"PFM 크라운","category":"치료·시술","short":"금속 위에 도자기를 입힌 크라운","detail":"PFM(Porcelain Fused to Metal) 크라운은 내부 금속 골격 위에 도자기를 소성하여 제작합니다. 강도는 좋으나 잇몸 변색이 생길 수 있습니다.","tags":["치료"],"link":"/treatments/crown"},
    {"term":"골드 크라운","category":"치료·시술","short":"금합금으로 만든 치아 캡","detail":"골드 크라운은 내구성이 가장 뛰어나고 치아 적합도가 우수합니다. 어금니에 적합하나 심미적이지 않아 보이지 않는 뒤쪽 치아에 주로 사용됩니다.","tags":["치료"],"link":"/treatments/crown"},
    {"term":"완전 틀니","category":"치료·시술","short":"모든 치아가 없을 때 사용하는 총의치","detail":"완전 틀니(Full Denture)는 위턱이나 아래턱의 모든 치아가 없을 때 사용하는 탈착식 보철입니다. 잇몸(점막)에 밀착되는 흡착력으로 유지됩니다.","tags":["치료"],"synonyms":["총의치","Full Denture"]},
    {"term":"부분 틀니","category":"치료·시술","short":"일부 치아가 없을 때 사용하는 국소의치","detail":"부분 틀니(Partial Denture)는 일부 치아가 없을 때 남은 치아에 걸쇠(클라스프)로 고정하는 탈착식 보철입니다.","tags":["치료"],"synonyms":["국소의치","Partial Denture"]},
    {"term":"정밀 틀니","category":"치료·시술","short":"고급 재료와 기술로 제작한 맞춤 틀니","detail":"정밀 틀니는 BPS(Biofunctional Prosthetic System) 등 정밀 인상과 기공 기술로 제작한 고급 틀니입니다. 밀착도와 심미성이 우수합니다.","tags":["치료"],"synonyms":["BPS 틀니"]},

    # ===== 기타 추가 =====
    {"term":"턱교정 수술","category":"치료·시술","short":"턱뼈를 외과적으로 이동시키는 수술","detail":"턱교정 수술(악교정 수술, Orthognathic Surgery)은 교정만으로 해결할 수 없는 골격성 부정교합을 턱뼈를 절골·이동시켜 교정하는 대수술입니다.","tags":["외과"],"synonyms":["Orthognathic Surgery"]},
    {"term":"이하선","category":"치아 구조","short":"귀 앞에 위치한 가장 큰 침샘","detail":"이하선(Parotid Gland)은 귀 앞에 위치한 인체 최대 침샘으로, 타액의 약 25%를 분비합니다. 이하선관은 위쪽 어금니 옆 볼 안쪽에 열립니다.","tags":["기본"],"synonyms":["Parotid"]},
    {"term":"치아 미백 종류","category":"치료·시술","short":"다양한 미백 방법과 차이점","detail":"전문가 미백(오피스)은 고농도 약제+광선으로 1시간 만에 효과를 보고, 자가 미백(홈)은 개인 트레이에 저농도 약제를 넣어 2주간 진행합니다.","tags":["심미"],"link":"/treatments/whitening"},
    {"term":"치아 색상 측정","category":"장비·기술","short":"치아 색을 객관적으로 측정하는 도구","detail":"Vita 쉐이드가이드는 A(적갈색)~D(회색) 4계열, 총 16단계로 치아 색을 분류하는 표준 도구입니다. 디지털 측색기로 더 객관적인 측정도 가능합니다.","tags":["장비"],"synonyms":["Vita 쉐이드가이드"]},
    {"term":"수술 가이드","category":"장비·기술","short":"임플란트 정밀 식립을 위한 3D 장치","detail":"수술 가이드(Surgical Guide)는 CT와 구강 스캔 데이터로 3D 프린팅 제작된 장치로, 임플란트를 계획된 위치·각도·깊이에 정밀하게 식립하도록 안내합니다.","tags":["장비"],"link":"/treatments/implant"},
    {"term":"치아 번호 체계","category":"전문 용어","short":"치아를 부르는 공식 명칭 체계","detail":"절치(앞니), 견치(송곳니), 소구치(작은어금니), 대구치(큰어금니)로 분류합니다. FDI 번호로 사분면(1~4)+위치(1~8)를 나타냅니다.","tags":["기타"]},
    {"term":"예방 치의학","category":"전문 용어","short":"치과 질환을 미리 예방하는 학문 분야","detail":"예방 치의학은 충치, 잇몸 질환 등을 사전에 예방하는 데 초점을 둔 치과 전문 분야입니다. 불소 도포, 실란트, 구강 위생 교육 등이 포함됩니다.","tags":["기타"]},
    {"term":"구강 보건 교육","category":"구강 관리","short":"올바른 구강 관리를 알려주는 교육","detail":"구강 보건 교육은 올바른 칫솔질, 치실 사용법, 식이 조절, 정기 검진 중요성 등을 알려주는 프로그램입니다. 어린이와 노인에게 특히 중요합니다.","tags":["예방"]},
    {"term":"치아 색 복원","category":"치료·시술","short":"변색된 치아를 원래 색으로 되돌리는 치료","detail":"치아 색 복원은 미백, 라미네이트, 레진 본딩 등으로 변색된 치아의 색상을 개선하는 치료입니다. 원인에 따라 적합한 방법이 다릅니다.","tags":["심미"],"link":"/treatments/whitening"},
    {"term":"클렌징","category":"구강 관리","short":"전문가가 시행하는 구강 세정","detail":"프로페셔널 클렌징(PMTC)은 치과위생사가 전문 기구와 연마제로 치아 표면의 플라크와 착색을 제거하고 불소를 도포하는 전문 세정 서비스입니다.","tags":["예방"],"synonyms":["PMTC"]},
    {"term":"치아 건강 체크리스트","category":"구강 관리","short":"일상에서 확인할 구강 건강 점검 항목","detail":"양치 시 잇몸 출혈, 구취, 시린 증상, 잇몸 부종, 치아 흔들림, 색 변화 등이 있으면 치과 방문이 필요하다는 위험 신호입니다.","tags":["예방"]},
    {"term":"디지털 치과","category":"전문 용어","short":"디지털 기술을 활용한 현대 치과 치료","detail":"디지털 치과는 3D 스캔, CAD/CAM, 네비게이션 임플란트, 디지털 미소 설계 등 최첨단 디지털 기술을 치과 진료에 접목한 것입니다.","tags":["기타"]},
    {"term":"환자 경험","category":"전문 용어","short":"병원 방문 전후의 전체적인 환자 만족도","detail":"환자 경험(Patient Experience)은 예약~진료~사후관리까지 전 과정에서의 만족도를 의미합니다. 서울비디치과는 환자 중심의 경험 설계를 지향합니다.","tags":["기타"]},
]

# 초성 추출 함수
CHOSUNG = ['ㄱ','ㄲ','ㄴ','ㄷ','ㄸ','ㄹ','ㅁ','ㅂ','ㅃ','ㅅ','ㅆ','ㅇ','ㅈ','ㅉ','ㅊ','ㅋ','ㅌ','ㅍ','ㅎ']
def get_chosung(ch):
    code = ord(ch) - 0xAC00
    if 0 <= code <= 11171:
        return CHOSUNG[code // 588]
    return ch

# 중복 확인 및 항목 추가
added = 0
skipped = 0
for entry in new_entries:
    if entry['term'] in existing_terms:
        skipped += 1
        continue
    
    item = {
        "id": next_id,
        "term": entry['term'],
        "chosung": get_chosung(entry['term'][0]),
        "category": entry['category'],
        "short": entry['short'],
        "detail": entry['detail'],
        "tags": entry.get('tags', []),
    }
    if 'synonyms' in entry:
        item['synonyms'] = entry['synonyms']
    if 'link' in entry:
        item['link'] = entry['link']
    
    existing_items.append(item)
    existing_terms.add(entry['term'])
    next_id += 1
    added += 1

# 카테고리 목록 재생성
categories = sorted(set(item['category'] for item in existing_items))

# 결과 저장
output = {
    "version": "2.0",
    "totalItems": len(existing_items),
    "categories": categories,
    "items": existing_items
}

with open('/home/user/webapp/public/data/encyclopedia.json', 'w') as f:
    json.dump(output, f, ensure_ascii=False, indent=2)

print(f"✅ 완료! 기존 187 + 신규 {added} = 총 {len(existing_items)}개")
print(f"⏭️ 중복 스킵: {skipped}개")
print(f"📂 카테고리: {len(categories)}개")
for cat in categories:
    count = sum(1 for i in existing_items if i['category'] == cat)
    print(f"  {cat}: {count}")
